diff --git a/mux.go b/mux.go
index 71620c0..3a293c3 100644
--- a/mux.go
+++ b/mux.go
@@ -291,6 +291,12 @@ func (mx *Mux) Mount(pattern string, handler http.Handler) {
 		panic(fmt.Sprintf("chi: attempting to Mount() a nil handler on '%s'", pattern))
 	}

+	// Normalize trailing slash so that Mount("/api/", h) and Mount("/api", h)
+	// behave identically: both /api and /api/ resolve to the sub-router.
+	if len(pattern) > 1 && pattern[len(pattern)-1] == '/' {
+		pattern = pattern[:len(pattern)-1]
+	}
+
 	// Provide runtime safety for ensuring a pattern isn't mounted on an existing
 	// routing pattern.
 	if mx.tree.findPattern(pattern+"*") || mx.tree.findPattern(pattern+"/*") {
